import{_ as e,c as l,o,a}from"./app.50048430.js";const b=JSON.parse('{"title":"\u6B63\u5219\u8868\u8FBE\u5F0F","description":"","frontmatter":{"title":"\u6B63\u5219\u8868\u8FBE\u5F0F","date":"2017-06-20T00:00:00.000Z","tags":["JS"]},"headers":[{"level":2,"title":"\u57FA\u7840","slug":"\u57FA\u7840"},{"level":2,"title":"JS \u4E2D\u7684\u5E94\u7528","slug":"js-\u4E2D\u7684\u5E94\u7528"},{"level":3,"title":"\u521B\u5EFA\u6B63\u5219\u5BF9\u8C61","slug":"\u521B\u5EFA\u6B63\u5219\u5BF9\u8C61"},{"level":3,"title":"\u9759\u6001\u5C5E\u6027","slug":"\u9759\u6001\u5C5E\u6027"},{"level":3,"title":"\u5B9E\u4F8B\u5C5E\u6027","slug":"\u5B9E\u4F8B\u5C5E\u6027"},{"level":3,"title":"\u5B9E\u4F8B\u65B9\u6CD5","slug":"\u5B9E\u4F8B\u65B9\u6CD5"},{"level":3,"title":"\u5B57\u7B26\u4E32\u5BF9\u8C61\u4E2D\u7684\u6B63\u5219","slug":"\u5B57\u7B26\u4E32\u5BF9\u8C61\u4E2D\u7684\u6B63\u5219"},{"level":2,"title":"\u8FDB\u9636","slug":"\u8FDB\u9636"},{"level":3,"title":"\u6355\u83B7\u7EC4","slug":"\u6355\u83B7\u7EC4"},{"level":3,"title":"\u53CD\u5411\u5F15\u7528","slug":"\u53CD\u5411\u5F15\u7528"},{"level":3,"title":"\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09","slug":"\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09"},{"level":3,"title":"\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09","slug":"\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09-1"}],"relativePath":"js/Regular-expression.md","lastUpdated":1661210647000}'),s={name:"js/Regular-expression.md"},p=a(`<h1 id="\u6B63\u5219\u8868\u8FBE\u5F0F" tabindex="-1">\u6B63\u5219\u8868\u8FBE\u5F0F <a class="header-anchor" href="#\u6B63\u5219\u8868\u8FBE\u5F0F" aria-hidden="true">#</a></h1><p><a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/RegExp" target="_blank" rel="noreferrer">MDN</a><a href="https://www.runoob.com/regexp/regexp-syntax.html" target="_blank" rel="noreferrer">\u83DC\u9E1F\u6559\u7A0B</a></p><p>\u6B63\u5219\u8868\u8FBE\u5F0F\u662F\u56FD\u9645\u6807\u51C6\uFF0C\u8DE8\u8BED\u8A00\u3002</p><p>\u6B63\u5219\u8868\u8FBE\u5F0F\u662F\u4E00\u4E2A\u89C4\u5219\uFF0C\u7528\u4E8E\u9A8C\u8BC1\u5B57\u7B26\u4E32\u3002</p><h2 id="\u57FA\u7840" tabindex="-1">\u57FA\u7840 <a class="header-anchor" href="#\u57FA\u7840" aria-hidden="true">#</a></h2><ol><li>\u5B57\u9762\u91CF\u5339\u914D</li></ol><p>\u89C4\u5219\u4E2D\u76F4\u63A5\u4E66\u5199\u5B57\u9762\u91CF\u5B57\u7B26</p><ol start="2"><li>\u7279\u6B8A\u5B57\u7B26</li></ol><ul><li><code>.</code> \u5339\u914D\u9664\u6362\u884C\u7B26\u4E4B\u5916\u7684\u4EFB\u4F55\u5355\u4E2A\u5B57\u7B26\u3002</li><li><code>^</code> \u5339\u914D\u8F93\u5165\u7684\u5F00\u59CB\u3002</li><li><code>$</code> \u5339\u914D\u8F93\u5165\u7684\u7ED3\u675F\u3002</li><li><code>()</code> \u6807\u8BB0\u4E00\u4E2A\u5B50\u8868\u8FBE\u5F0F\u7684\u5F00\u59CB\u548C\u7ED3\u675F\u4F4D\u7F6E</li></ul><ol start="3"><li>\u8F6C\u4E49\u7B26</li></ol><ul><li><code>\\n</code> \u5339\u914D\u4E00\u4E2A\u6362\u884C\u7B26</li><li><code>\\r</code> \u4E0D\u8981\u4F7F\u7528\uFF0C\u51FA\u73B0\u5728 Windows \u64CD\u4F5C\u7CFB\u7EDF\u4E2D\u3002</li><li><code>\\t</code> \u5339\u914D\u4E00\u4E2A\u5236\u8868\u7B26</li><li><code>\\s</code> \u5339\u914D\u4E00\u4E2A\u7A7A\u767D\u5B57\u7B26\uFF0C\u5305\u62EC\u7A7A\u683C\u3001\u5236\u8868\u7B26\u3001\u6362\u9875\u7B26\u548C\u6362\u884C\u7B26\u3002</li><li><code>\\S</code> \u5339\u914D\u4E00\u4E2A\u975E\u7A7A\u767D\u5B57\u7B26\u3002</li><li><code>\\b</code> \u5339\u914D\u4E00\u4E2A\u5355\u8BCD\u7684\u8FB9\u754C\u3002</li><li><code>\\B</code> \u5339\u914D\u4E00\u4E2A\u975E\u5355\u8BCD\u8FB9\u754C\u3002</li><li><code>\\d</code> \u5339\u914D\u4E00\u4E2A\u6570\u5B57\u3002\u7B49\u4EF7\u4E8E<code>[0-9]</code>\u3002</li><li><code>\\D</code> \u5339\u914D\u4E00\u4E2A\u975E\u6570\u5B57\u5B57\u7B26\u3002\u7B49\u4EF7\u4E8E<code>[^0-9]</code>\u3002</li><li><code>\\w</code> \u5339\u914D\u4E00\u4E2A\u5355\u5B57\u5B57\u7B26\uFF08\u5B57\u6BCD\u3001\u6570\u5B57\u6216\u8005\u4E0B\u5212\u7EBF\uFF09\u3002\u7B49\u4EF7\u4E8E <code>[A-Za-z0-9_]</code>\u3002</li><li><code>\\W</code> \u5339\u914D\u4E00\u4E2A\u975E\u5355\u5B57\u5B57\u7B26\u3002\u7B49\u4EF7\u4E8E <code>[^A-Za-z0-9_]</code>\u3002</li><li><code>\\uhhhh</code> \u5339\u914D\u4E00\u4E2A\u5341\u516D\u8FDB\u5236\u6570\u8868\u793A\u7684 Unicode \u5B57\u7B26\u3002<code>h</code>\u8868\u793A\u4E00\u4E2A\u5341\u516D\u8FDB\u5236\u7684 Unicode \u5B57\u7B26</li></ul><p>\u8F6C\u4E49\u7B26<code>\\</code>\u53EF\u4EE5\u5C06\u7279\u6B8A\u5B57\u7B26\u8F6C\u4E49</p><ol start="4"><li>\u5B57\u7B26\u96C6</li></ol><p><code>[\u5B57\u7B26\u8303\u56F4]</code><code>[^\u5B57\u7B26\u8303\u56F4]</code> \u5BF9\u5B57\u7B26\u8303\u56F4\u53D6\u53CD</p><p>\u5339\u914D\u4E2D\u6587\uFF1A<code>[\\u4e00-\\u9fa5]</code></p><ol start="5"><li>\u91CF\u8BCD</li></ol><p><strong>\u5339\u914D\u524D\u9762\u4E00\u4E2A\u8868\u8FBE\u5F0F\u51FA\u73B0\u7684\u6B21\u6570</strong></p><ul><li><code>*</code> \u5339\u914D\u524D\u4E00\u4E2A\u8868\u8FBE\u5F0F 0 \u6B21\u6216\u591A\u6B21\u3002\u7B49\u4EF7\u4E8E {0,}\u3002</li><li><code>+</code> \u5339\u914D\u524D\u4E00\u4E2A\u8868\u8FBE\u5F0F 1 \u6B21\u6216\u591A\u6B21\u3002\u7B49\u4EF7\u4E8E {1,}\u3002</li><li><code>?</code> \u5339\u914D\u524D\u9762\u4E00\u4E2A\u8868\u8FBE\u5F0F 0 \u6B21\u6216\u8005 1 \u6B21\u3002\u7B49\u4EF7\u4E8E {0,1}\u3002</li><li><code>{n}</code> \u5339\u914D n \u4E2A</li><li><code>{n,}</code> \u5339\u914D &gt;=n \u4E2A</li><li><code>{n,m}</code> \u5339\u914D n~m \u4E2A</li></ul><ol start="6"><li>\u6216\u8005</li></ol><p>\u591A\u4E2A\u89C4\u5219\u4E4B\u95F4\u9002\u7528\uFF0C\u6216\u8005<code>|</code>\uFF0C\u8868\u793A\u591A\u4E2A\u89C4\u5219\u4EFB\u9009\u5176\u4E00\u3002</p><h2 id="js-\u4E2D\u7684\u5E94\u7528" tabindex="-1">JS \u4E2D\u7684\u5E94\u7528 <a class="header-anchor" href="#js-\u4E2D\u7684\u5E94\u7528" aria-hidden="true">#</a></h2><p>JS \u4E2D\uFF0C\u6B63\u5219\u8868\u8FBE\u5F0F\u8868\u73B0\u4E3A\u4E00\u4E2A\u5BF9\u8C61\uFF0C\u662F\u901A\u8FC7\u6784\u9020\u51FD\u6570 RegExp \u521B\u5EFA\u7684</p><h3 id="\u521B\u5EFA\u6B63\u5219\u5BF9\u8C61" tabindex="-1">\u521B\u5EFA\u6B63\u5219\u5BF9\u8C61 <a class="header-anchor" href="#\u521B\u5EFA\u6B63\u5219\u5BF9\u8C61" aria-hidden="true">#</a></h3><ol><li><p>\u5B57\u9762\u91CF</p><p>\u7531\u659C\u6760\u5305\u56F4\u800C\u4E0D\u662F\u5F15\u53F7\u5305\u56F4\u3002<code>/\u6B63\u5219\u8868\u8FBE\u5F0F/</code></p></li><li><p>\u6784\u9020\u51FD\u6570\u6A21\u5F0F</p></li></ol><div class="language-js"><button class="copy"></button><span class="lang">js</span><pre><code><span class="line"><span style="color:#676E95;">//\u4EE5\u4E0B\u4E09\u79CD\u8868\u8FBE\u5F0F\u90FD\u4F1A\u521B\u5EFA\u76F8\u540C\u7684\u6B63\u5219\u8868\u8FBE\u5F0F\uFF1A</span></span>
<span class="line"><span style="color:#89DDFF;">;</span><span style="color:#89DDFF;">/</span><span style="color:#C3E88D;">ab</span><span style="color:#89DDFF;">+</span><span style="color:#C3E88D;">c</span><span style="color:#89DDFF;">/</span><span style="color:#F78C6C;">i</span></span>
<span class="line"><span style="color:#89DDFF;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">RegExp</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">ab+c</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">i</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#89DDFF;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">RegExp</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">/</span><span style="color:#C3E88D;">ab</span><span style="color:#89DDFF;">+</span><span style="color:#C3E88D;">c</span><span style="color:#89DDFF;">/</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">i</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span></code></pre></div><h3 id="\u9759\u6001\u5C5E\u6027" tabindex="-1">\u9759\u6001\u5C5E\u6027 <a class="header-anchor" href="#\u9759\u6001\u5C5E\u6027" aria-hidden="true">#</a></h3><ul><li><p>RegExp.lastIndex</p><p>\u8BE5\u7D22\u5F15\u8868\u793A\u4ECE\u54EA\u91CC\u5F00\u59CB\u4E0B\u4E00\u4E2A\u5339\u914D</p></li></ul><h3 id="\u5B9E\u4F8B\u5C5E\u6027" tabindex="-1">\u5B9E\u4F8B\u5C5E\u6027 <a class="header-anchor" href="#\u5B9E\u4F8B\u5C5E\u6027" aria-hidden="true">#</a></h3><ul><li><p>global</p><p>\u5224\u65AD\u662F\u5426\u5F00\u542F\u5168\u5C40\u5339\u914D\uFF0C\u6839\u636E\u60C5\u51B5\u8FD4\u56DE true \u6216 false\u3002</p></li><li><p>ignoreCase</p><p>\u662F\u5426\u5FFD\u7565\u5B57\u7B26\u5927\u5C0F\u5199\u3002</p></li><li><p>multiline</p><p>\u662F\u5426\u5F00\u542F\u591A\u884C\u6A21\u5F0F\u5339\u914D\u3002</p></li><li><p>source</p><p>\u5F97\u5230\u6B63\u5219\u8868\u8FBE\u5F0F\u7684\u6587\u672C\uFF0C\u4E0D\u5305\u62EC\u6B63\u5219\u5B57\u9762\u91CF\u4E24\u4FA7\u7684\u659C\u6760\u4E0E\u6807\u5FD7\u5B57\u7B26\u3002</p></li></ul><h3 id="\u5B9E\u4F8B\u65B9\u6CD5" tabindex="-1">\u5B9E\u4F8B\u65B9\u6CD5 <a class="header-anchor" href="#\u5B9E\u4F8B\u65B9\u6CD5" aria-hidden="true">#</a></h3><ul><li><p><code>test()</code></p><p>\u7528\u6765\u67E5\u770B\u6B63\u5219\u8868\u8FBE\u5F0F\u4E0E\u6307\u5B9A\u7684\u5B57\u7B26\u4E32\u662F\u5426\u5339\u914D\uFF0C\u8FD4\u56DE true \u6216 false\u3002</p></li><li><p><code>exec()</code></p><p>execute \u7684\u7F29\u5199\uFF0C\u6267\u884C\u5339\u914D\uFF0C\u5F97\u5230\u5339\u914D\u7684\u7ED3\u679C\uFF0C\u8FD4\u56DE\u4E00\u4E2A\u7ED3\u679C\u6570\u7EC4\u6216 null\u3002</p></li></ul><blockquote><p>\u6B63\u5219\u8868\u8FBE\u5F0F\uFF0C\u9ED8\u8BA4\u60C5\u51B5\uFF0C\u4F7F\u7528\u8D2A\u5A6A\u6A21\u5F0F\uFF08\u5C3D\u53EF\u80FD\u591A\u5339\u914D\uFF09</p></blockquote><blockquote><p>\u5728\u91CF\u8BCD\u540E\u9762\uFF0C\u52A0\u4E0A<code>?</code>\uFF0C\u8868\u793A\u8FDB\u5165\u975E\u8D2A\u5A6A\u6A21\u5F0F\u3002</p></blockquote><h3 id="\u5B57\u7B26\u4E32\u5BF9\u8C61\u4E2D\u7684\u6B63\u5219" tabindex="-1">\u5B57\u7B26\u4E32\u5BF9\u8C61\u4E2D\u7684\u6B63\u5219 <a class="header-anchor" href="#\u5B57\u7B26\u4E32\u5BF9\u8C61\u4E2D\u7684\u6B63\u5219" aria-hidden="true">#</a></h3><ul><li><p><code>match()</code></p><p>\u4F7F\u7528\u6B63\u5219\u8868\u8FBE\u5F0F\u4E0E\u5B57\u7B26\u4E32\u76F8\u6BD4\u8F83\u3002</p><p>\u8FD4\u56DE\u503C\uFF1A</p><ul><li>\u5982\u679C\u4F7F\u7528 g \u6807\u5FD7\uFF0C\u5219\u5C06\u8FD4\u56DE\u4E0E\u5B8C\u6574\u6B63\u5219\u8868\u8FBE\u5F0F\u5339\u914D\u7684\u6240\u6709\u7ED3\u679C\uFF0C\u4F46\u4E0D\u4F1A\u8FD4\u56DE\u6355\u83B7\u7EC4\u3002</li><li>\u5982\u679C\u672A\u4F7F\u7528 g \u6807\u5FD7\uFF0C\u5219\u4EC5\u8FD4\u56DE\u7B2C\u4E00\u4E2A\u5B8C\u6574\u5339\u914D\u53CA\u5176\u76F8\u5173\u7684\u6355\u83B7\u7EC4\uFF08Array\uFF09\u3002\u8FD4\u56DE\u7684\u6570\u7EC4\u6709\u9644\u52A0\u5C5E\u6027 <ul><li>groups: \u4E00\u4E2A\u6355\u83B7\u7EC4\u6570\u7EC4 \u6216 undefined\uFF08\u5982\u679C\u6CA1\u6709\u5B9A\u4E49\u547D\u540D\u6355\u83B7\u7EC4\uFF09\u3002</li><li>index: \u5339\u914D\u7684\u7ED3\u679C\u7684\u5F00\u59CB\u4F4D\u7F6E</li><li>input: \u641C\u7D22\u7684\u5B57\u7B26\u4E32.</li></ul></li></ul></li><li><p><code>search()</code></p><p>\u5BF9\u6B63\u5219\u8868\u8FBE\u5F0F\u548C\u6307\u5B9A\u5B57\u7B26\u4E32\u8FDB\u884C\u5339\u914D\u641C\u7D22\uFF0C\u8FD4\u56DE\u7B2C\u4E00\u4E2A\u51FA\u73B0\u7684\u5339\u914D\u9879\u7684\u4E0B\u6807\u3002</p></li><li><p><code>split()</code></p><p>\u4F7F\u7528\u6307\u5B9A\u7684\u5206\u9694\u7B26\u5B57\u7B26\u4E32\u5C06\u4E00\u4E2A String \u5BF9\u8C61\u5206\u5272\u6210\u5B50\u5B57\u7B26\u4E32\u6570\u7EC4\uFF0C\u4EE5\u4E00\u4E2A\u6307\u5B9A\u7684\u5206\u5272\u5B57\u4E32\u6765\u51B3\u5B9A\u6BCF\u4E2A\u62C6\u5206\u7684\u4F4D\u7F6E\u3002</p><p><strong>\u8BED\u6CD5\uFF1A</strong></p><blockquote><p>str.split([separator[, limit]])</p></blockquote><p><strong>\u53C2\u6570\uFF1A</strong></p><p><strong>separator</strong></p><blockquote><p>\u6307\u5B9A\u8868\u793A\u6BCF\u4E2A\u62C6\u5206\u5E94\u53D1\u751F\u7684\u70B9\u7684\u5B57\u7B26\u4E32\u3002separator \u53EF\u4EE5\u662F\u4E00\u4E2A\u5B57\u7B26\u4E32\u6216\u6B63\u5219\u8868\u8FBE\u5F0F\u3002</p></blockquote><p><strong>limit</strong></p><blockquote><p>\u4E00\u4E2A\u6574\u6570\uFF0C\u9650\u5B9A\u8FD4\u56DE\u7684\u5206\u5272\u7247\u6BB5\u6570\u91CF\u3002</p></blockquote></li><li><p><code>replace()</code> <a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/String/replace" target="_blank" rel="noreferrer">MDN</a></p><p>\u8FD4\u56DE\u66FF\u6362\u540E\u7684\u65B0\u5B57\u7B26\u4E32\uFF0C\u539F\u5B57\u7B26\u4E32\u4E0D\u4F1A\u6539\u53D8\u3002</p><p><strong>\u8BED\u6CD5\uFF1A</strong></p><blockquote><p><code>str.replace(regexp | substr, newSubStr | function)</code></p></blockquote><p><strong>\u53C2\u6570\uFF1A</strong></p><p><strong>regexp (pattern)</strong></p><blockquote><p>\u4E00\u4E2A RegExp \u5BF9\u8C61\u6216\u8005\u5176\u5B57\u9762\u91CF\u3002\u8BE5\u6B63\u5219\u6240\u5339\u914D\u7684\u5185\u5BB9\u4F1A\u88AB\u7B2C\u4E8C\u4E2A\u53C2\u6570\u7684\u8FD4\u56DE\u503C\u66FF\u6362\u6389\u3002</p></blockquote><p><strong>substr (pattern)</strong></p><blockquote><p>\u4E00\u4E2A\u5C06\u88AB newSubStr \u66FF\u6362\u7684 \u5B57\u7B26\u4E32\u3002\u5176\u88AB\u89C6\u4E3A\u4E00\u6574\u4E2A\u5B57\u7B26\u4E32\uFF0C\u800C\u4E0D\u662F\u4E00\u4E2A\u6B63\u5219\u8868\u8FBE\u5F0F\u3002\u4EC5\u7B2C\u4E00\u4E2A\u5339\u914D\u9879\u4F1A\u88AB\u66FF\u6362\u3002</p></blockquote><p><strong>newSubStr (replacement)</strong></p><blockquote><p>\u7528\u4E8E\u66FF\u6362\u6389\u7B2C\u4E00\u4E2A\u53C2\u6570\u5728\u539F\u5B57\u7B26\u4E32\u4E2D\u7684\u5339\u914D\u90E8\u5206\u7684\u5B57\u7B26\u4E32\u3002\u8BE5\u5B57\u7B26\u4E32\u4E2D\u53EF\u4EE5\u5185\u63D2\u4E00\u4E9B\u7279\u6B8A\u7684\u53D8\u91CF\u540D\u3002</p></blockquote><p><strong>function (replacement)</strong></p><blockquote><p>\u4E00\u4E2A\u7528\u6765\u521B\u5EFA\u65B0\u5B50\u5B57\u7B26\u4E32\u7684\u51FD\u6570\uFF0C\u8BE5\u51FD\u6570\u7684\u8FD4\u56DE\u503C\u5C06\u66FF\u6362\u6389\u7B2C\u4E00\u4E2A\u53C2\u6570\u5339\u914D\u5230\u7684\u7ED3\u679C\u3002</p></blockquote></li></ul><h2 id="\u8FDB\u9636" tabindex="-1">\u8FDB\u9636 <a class="header-anchor" href="#\u8FDB\u9636" aria-hidden="true">#</a></h2><h3 id="\u6355\u83B7\u7EC4" tabindex="-1">\u6355\u83B7\u7EC4 <a class="header-anchor" href="#\u6355\u83B7\u7EC4" aria-hidden="true">#</a></h3><p>\u7528\u5C0F\u62EC\u53F7\u5305\u88F9\u7684\u90E8\u5206\u53EB\u505A\u6355\u83B7\u7EC4\uFF0C\u6355\u83B7\u7EC4\u4F1A\u51FA\u73B0\u5728\u5339\u914D\u7ED3\u679C\u4E2D\u3002</p><p><code>(\u6B63\u5219\u8868\u8FBE\u5F0F)</code></p><p>\u6355\u83B7\u7EC4\u53EF\u4EE5\u547D\u540D\uFF0C\u53EB\u505A\u5177\u540D\u6355\u83B7\u7EC4\u3002\u5728\u5C0F\u62EC\u53F7\u524D\u6DFB\u52A0 <code>?&lt;\u6355\u83B7\u7EC4\u540D\u5B57&gt;</code></p><p><code>(?&lt;\u6355\u83B7\u7EC4\u540D\u5B57&gt;\u6B63\u5219\u8868\u8FBE\u5F0F)</code></p><p>\u975E\u6355\u83B7\u7EC4 \u5728\u5C0F\u62EC\u53F7\u524D\u6DFB\u52A0 <code>?:</code></p><p><code>(?:\u6B63\u5219\u8868\u8FBE\u5F0F)</code></p><h3 id="\u53CD\u5411\u5F15\u7528" tabindex="-1">\u53CD\u5411\u5F15\u7528 <a class="header-anchor" href="#\u53CD\u5411\u5F15\u7528" aria-hidden="true">#</a></h3><p>\u5728\u6B63\u5219\u8868\u8FBE\u5F0F\u4E2D\uFF0C\u4F7F\u7528\u67D0\u4E2A\u6355\u83B7\u7EC4\uFF0C<code>\\\u6355\u83B7\u7EC4\u7F16\u53F7</code></p><h3 id="\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09" tabindex="-1">\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09 <a class="header-anchor" href="#\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09" aria-hidden="true">#</a></h3><p>\u68C0\u67E5\u67D0\u4E2A\u5B57\u7B26\u540E\u9762\u7684\u5B57\u7B26<strong>\u662F\u5426\u6EE1\u8DB3\u67D0\u4E2A\u89C4\u5219</strong>\uFF0C\u8BE5\u89C4\u5219\u4E0D\u6210\u4E3A\u5339\u914D\u7ED3\u679C\uFF0C\u5E76\u4E14\u4E0D\u6210\u4E3A\u6355\u83B7\u7EC4\u3002 <code>(?=\u6B63\u5219\u8868\u8FBE\u5F0F)</code></p><h3 id="\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09-1" tabindex="-1">\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09 <a class="header-anchor" href="#\u6B63\u5411\u65AD\u8A00\uFF08\u9884\u67E5\uFF09-1" aria-hidden="true">#</a></h3><p>\u68C0\u67E5\u67D0\u4E2A\u5B57\u7B26\u540E\u9762\u7684\u5B57\u7B26<strong>\u662F\u5426\u4E0D\u6EE1\u8DB3\u67D0\u4E2A\u89C4\u5219</strong>\uFF0C\u8BE5\u89C4\u5219\u4E0D\u6210\u4E3A\u5339\u914D\u7ED3\u679C\uFF0C\u5E76\u4E14\u4E0D\u6210\u4E3A\u6355\u83B7\u7EC4\u3002<code>(?!\u6B63\u5219\u8868\u8FBE\u5F0F)</code></p>`,49),t=[p];function c(n,r,i,d,h,u){return o(),l("div",null,t)}const D=e(s,[["render",c]]);export{b as __pageData,D as default};
